prompt:
Implement a JavaScript `Router` class for URL pattern matching with path parameters.

API:
- `router.add(method, pattern, handler)` — register a route with :param placeholders
- `router.match(method, path)` — returns `{ handler, params }` or `null` if no match

Include this test code at the end:

const router = new Router();
router.add('GET', '/users', 'listUsers');
router.add('GET', '/users/:id', 'getUser');
router.add('POST', '/users/:id/posts/:postId', 'getPost');
router.add('DELETE', '/users/:id', 'deleteUser');

const r1 = router.match('GET', '/users');
console.log(r1.handler, JSON.stringify(r1.params));

const r2 = router.match('GET', '/users/42');
console.log(r2.handler, JSON.stringify(r2.params));

const r3 = router.match('POST', '/users/7/posts/99');
console.log(r3.handler, JSON.stringify(r3.params));

const r4 = router.match('GET', '/unknown');
console.log(r4);

const r5 = router.match('DELETE', '/users/42');
console.log(r5.handler, JSON.stringify(r5.params));
